changeSet.sql:
ALTER TABLE organization_requirement_control_test_results ADD COLUMN evidence_eligible boolean;
ALTER TABLE system_requirement_control_test_results ADD COLUMN evidence_eligible boolean;

CREATE TABLE security_audit_comments
(
	id serial,
	organization_id integer DEFAULT NULL,
	comment text NOT NULL,
	created_by_id integer DEFAULT NULL,
	updated_by_id integer DEFAULT NULL,
	created_at timestamp without time zone NOT NULL DEFAULT now(),
	updated_at timestamp without time zone NOT NULL DEFAULT now(),

	CONSTRAINT pk_security_audit_comments PRIMARY KEY (id)
	, CONSTRAINT fk_security_audit_comments_to_organization FOREIGN KEY (organization_id) REFERENCES organizations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_security_audit_comments_to_user FOREIGN KEY (created_by_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_security_audit_comments_user ON security_audit_comments (created_by_id);

CREATE TABLE security_audit_comment_to_system_requirement_control_test_results
(
	id serial,
	security_audit_comment_id integer NOT NULL,
	system_requirement_control_test_result_id integer DEFAULT NULL,

	CONSTRAINT pk_security_audit_comment_to_system_requirement_control_test_result PRIMARY KEY (id)
	, CONSTRAINT fk_sac2srctr_to_security_audit_comments FOREIGN KEY (security_audit_comment_id) REFERENCES security_audit_comments (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
	, CONSTRAINT fk_sac2srctr_to_system_requirement_control_test_results FOREIGN KEY (system_requirement_control_test_result_id) REFERENCES system_requirement_control_test_results (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
);
CREATE INDEX i_sac2srctr_to_security_audit_comment ON security_audit_comment_to_system_requirement_control_test_results (security_audit_comment_id);
CREATE INDEX i_sac2srctr_to_system_requirement_control_test_result ON security_audit_comment_to_system_requirement_control_test_results (system_requirement_control_test_result_id);

CREATE TABLE security_audit_comment_to_organization_requirement_control_test_results
(
	id serial,
	security_audit_comment_id integer NOT NULL,
	organization_requirement_control_test_result_id integer DEFAULT NULL,

	CONSTRAINT pk_security_audit_comment_to_organization_requirement_control_test_result PRIMARY KEY (id)
	, CONSTRAINT fk_sac2orctr_to_security_audit_comments FOREIGN KEY (security_audit_comment_id) REFERENCES security_audit_comments (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
	, CONSTRAINT fk_sac2orctr_to_organization_requirement_control_test_results FOREIGN KEY (organization_requirement_control_test_result_id) REFERENCES organization_requirement_control_test_results (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
);
CREATE INDEX i_sac2orctr_to_security_audit_comment ON security_audit_comment_to_organization_requirement_control_test_results (security_audit_comment_id);
CREATE INDEX i_sac2orctr_to_organization_requirement_control_test_result ON security_audit_comment_to_organization_requirement_control_test_results (organization_requirement_control_test_result_id);

rollback.sql:
DROP TABLE IF EXISTS security_audit_comment_to_organization_requirement_control_test_results;
DROP TABLE IF EXISTS security_audit_comment_to_system_requirement_control_test_results;
DROP TABLE IF EXISTS security_audit_comments;
